'use strict';

var i18n = require('../i18n.js');
var index = require('../cache/index.js');
var constants = require('../constants.js');
var notify = require('./notify.js');

function createI18nMiddleware({ srcPath, notifyMissingTranslations, I18nClass: I18nCustomClass, } = {}) {
    index.i18nCache.initialize(srcPath || constants.DEFAULT_SRC_PATH);
    const I18nClass = I18nCustomClass ?? i18n.I18n;
    const i18nMiddleware = (req, res, next) => {
        const { locale: customLocale, platform } = req;
        const countryId = platform?.countryId || undefined;
        const locale = customLocale || (countryId && index.i18nCache.getLocale(countryId));
        const translations = locale ? index.i18nCache.getTranslations(locale) : {};
        req.translations = translations;
        req.i18n = new I18nClass({
            locale,
            translations,
            notifyMissingTranslations,
            notify: notify.notify,
        });
        next();
    };
    return i18nMiddleware;
}

exports.createI18nMiddleware = createI18nMiddleware;
